INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'In September 2023, which country claimed to have successfully launched an imaging satellite Noor-3 into space?', 'Iran', 'Turkey', 'Saudi Arabia', 'Qatar', 1, 'Iran successfully launched the Noor-3 imaging satellite in September 2023, marking another milestone in its space program.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'León Marchand, who made news with his record-breaking performance, is associated with which of the following sports?', 'Chess', 'Swimming', 'Boxing', 'Tennis', 2, 'Léon Marchand is a French swimmer who broke Michael Phelps'' world record in the 400m individual medley at the 2023 World Championships.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Where was India''s first 3D printed post office inaugurated in August 2023?', 'Ahmedabad', 'Mumbai', 'Hyderabad', 'Bengaluru', 3, 'India''s first 3D printed post office was inaugurated in Bengaluru (Cambridge Layout) in August 2023, constructed using 3D printing technology.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Which of the following vehicle successfully launched Chandrayaan-3 into orbit?', 'LVM3 M4', 'PSLV-C57', 'PSLV-C48', 'GSLV Mk II', 1, 'Chandrayaan-3 was launched on July 14, 2023, using the LVM3-M4 (Launch Vehicle Mark-3) rocket from Satish Dhawan Space Centre.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'GPS Aided Geo Augmented Navigation (GAGAN) has been developed as a regional Satellite Based Augmentation System (SBAS) by ______. I. Airports Authority of India (AAI) II. Indian Space Research Organization (ISRO)', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'GAGAN was developed jointly by AAI and ISRO to provide accurate GPS navigation signals for aviation and other applications.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'As of November 2023, researchers from ______ have developed a new artificial light-harvesting system that can efficiently capture light for power conversion by mimicking photosynthesis. I. IISER-Thiruvananthapuram II. IIT-Indore', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Researchers from IISER-Thiruvananthapuram developed the artificial light-harvesting system mimicking photosynthesis for efficient power conversion.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding e-Krishi Samvad? I. This internet-based interface was launched in 2017. II. This is a unique platform that provides direct and effective solutions to the problems faced by farmers and stakeholders in the agriculture sector.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'e-Krishi Samvad was launched in 2016 (not 2017). Statement I is incorrect. It is indeed a unique platform providing solutions to farmers, so Statement II is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'In November 2021, ______, under the aegis of Ministry of Education, conducted the National Achievement Survey throughout the country.', 'CBSE', 'NCERT', 'AICTE', 'ITI', 2, 'NCERT conducted the National Achievement Survey (NAS) in November 2021 under the Ministry of Education to assess learning outcomes of students.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'One Stop Centre (OSC) Scheme is implemented by which Ministry of the Government of India?', 'Ministry of Health and Family Welfare', 'Ministry of Women and Child Development', 'Ministry of Road Transport and Highways', 'Ministry of Social Justice and Empowerment', 2, 'The One Stop Centre (OSC) Scheme, also known as Sakhi, is implemented by the Ministry of Women and Child Development to support women affected by violence.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Pradhan Mantri Shram Yogi Maandhan is a government scheme meant for which of the following? I. Old age protection II. Social security of Unorganized workers', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'PM Shram Yogi Maandhan provides old age protection and social security to unorganized workers through a monthly pension after age 60.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Which of the following Goals of the 2030 Agenda for Sustainable Development seeks to ensure inclusive and equitable quality education and promote lifelong learning opportunities for all?', 'Goal 3', 'Goal 4', 'Goal 5', 'Goal 6', 2, 'Sustainable Development Goal 4 (SDG 4) aims to ensure inclusive and equitable quality education and promote lifelong learning opportunities for all.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'In November 2021, the Government of India Constituted a High-Level Committee to develop a National Credit Accumulation & Transfer Framework for both Vocational and General Education under the chairmanship of ______.', 'Neelam Shammi Rao', 'Sridhar Srivastava', 'Manoj Ahuja', 'Nirmaljeet Singh Kalsi', 4, 'The High-Level Committee for National Credit Accumulation & Transfer Framework was chaired by Nirmaljeet Singh Kalsi in November 2021.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'In the context of the National Education Policy 2020, which of the following statements is/are correct regarding the new pedagogical and curricular structure? I. A strong base of Early Childhood Care and Education from age 3 is included in the 5+3+3+4 structure. II. A National Mission on Foundational Literacy and Numeracy will be set up by the Ministry of Human Resource Development.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: NEP 2020 introduces 5+3+3+4 structure with ECCE from age 3, and establishes a National Mission on Foundational Literacy and Numeracy.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'The Asian Games 2023 was held in ______.', 'Shenzhen', 'Hangzhou', 'Guangzhou', 'Chongqing', 2, 'The 19th Asian Games 2023 were held in Hangzhou, China from September to October 2023.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'The Indian men''s hockey team won the Asian Champions Trophy 2023 after defeating ______ in the final.', 'Malaysia', 'Japan', 'Korea', 'Pakistan', 1, 'India defeated Malaysia 4-3 in the final of the Asian Champions Trophy 2023 held in Chennai.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Sagar Kailas Owhalkar is associated with which of the following sports?', 'Badminton', 'Kabaddi', 'Shooting', 'Mallakhamb', 4, 'Sagar Kailas Owhalkar is a renowned Mallakhamb athlete, a traditional Indian sport involving gymnastics on a pole or rope.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Who was honoured with the Tenzing Norgay National Adventure Award in the Water Adventure category for the year 2021?', 'Naina Dhakad', 'Shubham Dhananjay Vanmali', 'Kunwar Bhawani Singh Samyal', 'Priyanka Mohite', 2, 'Shubham Dhananjay Vanmali received the Tenzing Norgay National Adventure Award 2021 in the Water Adventure category.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct in the context of National Games 2022? I. Haryana won the joint highest number of silver medals. II. Delhi won the second highest number of bronze medals.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Haryana won the joint highest number of silver medals (10) with Gujarat. Delhi won the highest (not second highest) number of bronze medals (12). Statement I is correct, II is incorrect.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Who of the following won the Arjuna Awards 2022 in chess? I. Bhakti Pradip Kulkarni II. R Praggnanandhaa', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'R Praggnanandhaa won the Arjuna Award in 2022 for chess. Bhakti Pradip Kulkarni did not receive the award in 2022.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Normally rain water has a pH of ______.', '3.8', '4.2', '5.6', '6.4', 3, 'Normal rainwater has a pH of about 5.6 due to the presence of carbon dioxide forming carbonic acid. Lower pH indicates acid rain.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following constitutes the biotic component of the biosphere? I. Plants II. Air', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Plants are biotic (living) components of the biosphere. Air is abiotic (non-living). So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding Chlorofluorocarbons (CFCs)? I. CFCs are used in refrigerators, air conditioners, and aerosol sprays. II. CFCs damage the ozone layer in the atmosphere.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: CFCs are used in refrigerators, ACs, and aerosol sprays, and they deplete the ozone layer in the stratosphere.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following is a natural source of tartaric acid?', 'Tamarind', 'Tomato', 'Vinegar', 'Brinjal', 1, 'Tamarind is a natural source of tartaric acid. Vinegar contains acetic acid, tomatoes contain citric acid.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Anaemia is caused by the deficiency of ______.', 'Vitamin D', 'Phosphorus', 'Iodine', 'Iron', 4, 'Anaemia is caused by iron deficiency, which leads to reduced hemoglobin production and decreased oxygen-carrying capacity of blood.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding Mycoplasma? I. They completely lack a cell wall. II. They can survive without oxygen.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Mycoplasma lack a cell wall and can survive without oxygen (facultative anaerobes). Both statements are correct.', 'medium')
